import * as v from 'valibot'

const supabasePublicConfigSchema = v.object({
    url: v.string(),
    anonKey: v.string(),
})

type SupabasePublicConfig = v.InferOutput<typeof supabasePublicConfigSchema>

const supabasePublicConfig = v.parse(supabasePublicConfigSchema, {
    url: process.env.NEXT_PUBLIC_SUPABASE_URL,
    anonKey: process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
})

export function getSupabaseConfig(): SupabasePublicConfig {
    return { ...supabasePublicConfig }
}

package commands

import "errors"

type ProgressStatus string

const (
	ProgressStatusInProgress ProgressStatus = "IN_PROGRESS"
	ProgressStatusCompleted  ProgressStatus = "COMPLETED"
)

var ErrInvalidProgressStatus = errors.New("invalid progress status")

func ParseProgressStatus(s string) (ProgressStatus, error) {
	switch ProgressStatus(s) {
	case ProgressStatusInProgress, ProgressStatusCompleted:
		return ProgressStatus(s), nil
	}
	return "", ErrInvalidProgressStatus
}

