import (
	"context"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type SqrcUserTopicProgressRepository struct {
	sqrc db.Querier
}

func NewSqrcUserTopicProgressRepository(q db.Querier) *SqrcUserTopicProgressRepository {
	return &SqrcUserTopicProgressRepository{sqrc: q}
}

func (repository *SqrcUserTopicProgressRepository) upsert(ctx context.Context, userId, topicId string, status ProgressStatus) error {
	var userIdUuid, topicIdUuid pgtype.UUID
	if err := userIdUuid.Scan(userId); err != nil {
		return err
	}
	if err := topicIdUuid.Scan(topicId); err != nil {
		return err
	}

	return repository.sqrc.UpsertProgress(ctx, db.UpsertProgressParams{
		Coursesectiontopicid: topicIdUuid,
		Userid:               userIdUuid,
		Status:               string(status),
	})
}

