		h.PatchEnrollmentHandler(w, req)

		if w.Result().StatusCode != http.StatusOK {
			t.Errorf("ステータスコードが200であること: got %d", w.Result().StatusCode)
		}
		body := decodeMap(t, w)
		if body["status"] != "COMPLETED" {
			t.Errorf("statusが一致すること: got %q", body["status"])
		}
	})
}

