		if err != nil {
			t.Fatalf("エラーが発生しないこと: %v", err)
		}
		if s != ProgressStatusCompleted {
			t.Errorf("値が一致すること: got %q", s)
		}
	})

	t.Run("不正値はErrInvalidProgressStatusを返す", func(t *testing.T) {
