	t.Run("空文字はErrInvalidProgressStatusを返す", func(t *testing.T) {
		_, err := ParseProgressStatus("")
		if !errors.Is(err, ErrInvalidProgressStatus) {
			t.Errorf("ErrInvalidProgressStatusが返ること: got %v", err)
		}
	})
