package commands

import (
	"context"

	"github.com/google/uuid"
)

type UpdateEnrollmentParams struct {
	userId   uuid.UUID
	courseId string
	topicId  uuid.UUID
	status   string
}

type UpdateEnrollmentResult struct {
	TopicId string
	Status  string
}

type CourseRepository interface {
	getCourseByCourseId(ctx context.Context, courseId string) (Course, error)
}

type ProgressRepository interface {
	upsert(ctx context.Context, progress EnrollmentProgress) error
}

type UpdateEnrollmentUsecaseInterface interface {
	execute(ctx context.Context, params UpdateEnrollmentParams) (UpdateEnrollmentResult, error)
}

type UpdateEnrollmentUsecase struct {
	courseRepository   CourseRepository
	progressRepository ProgressRepository
}

func NewUpdateEnrollmentUsecase(courseRepo CourseRepository, progressRepo ProgressRepository) UpdateEnrollmentUsecase {
	return UpdateEnrollmentUsecase{
		courseRepository:   courseRepo,
		progressRepository: progressRepo,
	}
}

func (usecase UpdateEnrollmentUsecase) execute(ctx context.Context, params UpdateEnrollmentParams) (UpdateEnrollmentResult, error) {
	course, err := usecase.courseRepository.getCourseByCourseId(ctx, params.courseId)
	if err != nil {
		return UpdateEnrollmentResult{}, err
	}

	if err := course.checkEnrollable(params.userId); err != nil {
		return UpdateEnrollmentResult{}, err
	}

	topic, err := course.findTopicById(params.topicId)
	if err != nil {
		return UpdateEnrollmentResult{}, err
	}

	userId, err := uuid.Parse(params.userId)
	if err != nil {
		return UpdateEnrollmentResult{}, err
	}
	topicId, err := uuid.Parse(topic.topicId)
	if err != nil {
		return UpdateEnrollmentResult{}, err
	}

	progress := NewEnrollmentProgress(userId, topicId)
	switch ProgressStatus(params.status) {
	case ProgressStatusInProgress:
		progress.Start()
	case ProgressStatusCompleted:
		progress.Finish()
	default:
		return UpdateEnrollmentResult{}, ErrInvalidProgressStatus
	}

	if err := usecase.progressRepository.upsert(ctx, progress); err != nil {
		return UpdateEnrollmentResult{}, err
	}

	return UpdateEnrollmentResult{
		TopicId: progress.TopicId().String(),
		Status:  string(progress.Status()),
	}, nil
}

